# frozen_string_literal: true
#
# Ruby port of examples/c/hello-world.c using the autogenerated Ruby
# bindings (see doc/src/codegen/v2/lang_ruby/). Same data flow as
# Lua/Python — a single-counter model is wrapped in `Azul::RefAny`,
# the layout callback rebuilds the DOM each frame, and the click
# handler increments the counter.
#
# Callbacks go through libazul's host-invoker plumbing
# (`AzCallback_createFromHostHandle`, `AzApp_setCallbackInvoker`)
# so the Ruby callable is held alive by the framework's RefAny
# refcount. There's no per-callback FFI::Function pin to manage.
#
# Run with:
#     ruby -Ipath/to/azul.rb hello-world.rb
#
# Requires the `ffi` gem.

require 'azul'

# Convenience aliases — we deliberately do NOT `include Azul` because
# that would shadow Ruby's built-in `String` with `Azul::String`.
App                       = Azul::App
AppConfig                 = Azul::AppConfig
Button                    = Azul::Button
ButtonType                = Azul::ButtonType
CssProperty               = Azul::CssProperty
CssPropertyWithConditions = Azul::CssPropertyWithConditions
Dom                       = Azul::Dom
RefAny                    = Azul::RefAny
StyleFontSize             = Azul::StyleFontSize
Update                    = Azul::Update
WindowCreateOptions       = Azul::WindowCreateOptions
WindowDecorations         = Azul::WindowDecorations
WindowBackgroundMaterial  = Azul::WindowBackgroundMaterial
AzString                  = Azul::String

# ── Data model ──────────────────────────────────────────────────────
#
# `RefAny.wrap(obj)` stashes `obj` in an internal id-keyed table and
# returns an `AzRefAny` whose payload is just the id. The framework's
# RefAny destructor calls back through the registered host releaser to
# drop the entry when the last clone goes away.

model = { counter: 5 }
data  = RefAny.wrap(model)

# ── Callback: button click ──────────────────────────────────────────

on_click = lambda do |data_ptr, _info_ptr|
  m = RefAny.unwrap(data_ptr)
  next Update::DoNothing if m.nil?
  m[:counter] += 1
  Update::RefreshDom
end

# ── Callback: layout (rebuilds DOM each frame) ──────────────────────

layout = lambda do |data_ptr, _info_ptr|
  m = RefAny.unwrap(data_ptr)
  next Dom.create_body if m.nil?

  # Counter label (wrapped in a div so the font-size sticks)
  label = Dom.create_text(AzString.copy_from_string(m[:counter].to_s))
  label_wrapper = Dom.create_div
  label_wrapper.add_css_property(
    CssPropertyWithConditions.simple(
      CssProperty.font_size(StyleFontSize.px(32.0))
    )
  )
  label_wrapper.add_child(label)

  # Increment button. The wrapper auto-routes `on_click` through
  # `Azul._register_callback('Callback', ...)` — we just pass the lambda.
  button = Button.create(AzString.copy_from_string('Increase counter'))
  button.set_button_type(ButtonType::Primary)
  button.set_on_click(RefAny.clone(data_ptr), on_click)
  button_dom = button.dom

  # Body
  body = Dom.create_body
  body.add_child(label_wrapper)
  body.add_child(button_dom)
  body
end

# ── Main ────────────────────────────────────────────────────────────

window = WindowCreateOptions.create(layout)
window.window_state.title = AzString.copy_from_string('Hello World')
window.window_state.size.dimensions.width  = 400.0
window.window_state.size.dimensions.height = 300.0

# NoTitleAutoInject: OS draws close/min/max buttons,
# framework auto-injects a Titlebar with drag support.
window.window_state.flags.decorations         = WindowDecorations::NoTitleAutoInject
window.window_state.flags.background_material = WindowBackgroundMaterial::Sidebar

app = App.create(data, AppConfig.create)
app.run(window)
